            c.setConnectTimeout(30000); c.setReadTimeout(60000)
            if (ssl) { try {
                def sc = javax.net.ssl.SSLContext.getInstance("TLS")
                sc.init(null, [new javax.net.ssl.X509TrustManager() {
                    void checkClientTrusted(java.security.cert.X509Certificate[] x, String a) {}
                    void checkServerTrusted(java.security.cert.X509Certificate[] x, String a) {}
                    java.security.cert.X509Certificate[] getAcceptedIssuers() { null }
                }] as javax.net.ssl.TrustManager[], new java.security.SecureRandom())
                c.setSSLSocketFactory(sc.getSocketFactory()); c.setHostnameVerifier({ h, s -> true })
            } catch (Exception ex) {} }
            if (c.getResponseCode() != 200) throw new RuntimeException("HTTP ${c.getResponseCode()}")
            return c.getInputStream().text
        }
    }
}

try {
    def client = new ThanosClient(hostProps)
    def instant = [
        "memory_available_bytes": 'kubevirt_vmi_memory_available_bytes',
        "memory_used_bytes": 'kubevirt_vmi_memory_used_bytes',
        "memory_domain_bytes": 'kubevirt_vmi_memory_domain_bytes',
        "memory_resident_bytes": 'kubevirt_vmi_memory_resident_bytes',
        "memory_cached_bytes": 'kubevirt_vmi_memory_cached_bytes',
        "memory_usable_bytes": 'kubevirt_vmi_memory_usable_bytes',
        "memory_unused_bytes": 'kubevirt_vmi_memory_unused_bytes',
        "memory_balloon_bytes": 'kubevirt_vmi_memory_actual_balloon_bytes'
    ]
    def rates = [
        "memory_swap_in_rate": 'rate(kubevirt_vmi_memory_swap_in_traffic_bytes[5m])',
        "memory_swap_out_rate": 'rate(kubevirt_vmi_memory_swap_out_traffic_bytes[5m])',
        "memory_pgmajfault_rate": 'rate(kubevirt_vmi_memory_pgmajfault_total[5m])',
        "memory_pgminfault_rate": 'rate(kubevirt_vmi_memory_pgminfault_total[5m])'
    ]
    def allData = [:]

    instant.each { dp, q -> client.queryGroupedByKey(q, ["namespace", "name"]).each { k, v -> if (!allData[k]) allData[k] = [:]; allData[k][dp] = v } }
    rates.each { dp, q -> client.queryGroupedByKey(q, ["namespace", "name"]).each { k, v -> if (!allData[k]) allData[k] = [:]; allData[k][dp] = v } }

    allData.each { wv, dps ->
        dps.each { dp, val -> if (val != null) println "${wv}.${dp}=${val}" }
        def domain = dps["memory_domain_bytes"]
        def avail = dps["memory_available_bytes"]
        if (domain && avail) {
            try {
                def d = domain as Double
                def a = avail as Double
                if (d > 0) println "${wv}.memory_usage_percent=${String.format('%.2f', ((d - a) / d) * 100)}"
            } catch (Exception e) {}
        }
    }
    return 0
} catch (Exception e) {
    System.err.println "ERROR: ${e.message}"
    return 1
}
